```c++
int integerBreak(int n)
{
    vector<int> dp(n + 1, 0);
    dp[2] = 1;
    // dp[3] = 2;
    // dp[4] = 4;
    for (int i = 3; i <= n; i++)
    {
        for (int j = 2; j < i; ++j)
        {
            dp[i] = max(max(dp[i], (i - j) * j), dp[i - j] * j);
            // cout << i << " " << dp[i] << endl;
        }
    }
    return dp[n];
}
