#include <iostream>
#include <set>
using namespace std;

int main()
{
    set<long long int> s;
    s.insert(1);
    set<long long int>::iterator it;
    it = s.begin();
    for (int i = 0; i < 1500; i++)
    {
        long long int num = *it;
        if (!s.count(num * 2))
            s.insert(num * 2);
        if (!s.count(num * 3))
            s.insert(num * 3);
        if (!s.count(num * 5))
            s.insert(num * 5);
        *it++;
    }
    int i = 0;
    for (it = s.begin(); it != s.end(); it++)
    {
        ++i;
        if (i == 1500)
            cout << "The 1500'th ugly number is " << *it << ".\n";
        // cout << ++i << "***" << *it << endl;
    }

    return 0;
}
```

